40: func (p RESTStorageProvider) NewRESTStorage(apiResourceConfigSource serverstorage.APIResourceConfigSource, restOptionsGetter generic.RESTOptionsGetter) (genericapiserver.APIGroupInfo, error) {
41: 	apiGroupInfo := genericapiserver.NewDefaultAPIGroupInfo(resource.GroupName, legacyscheme.Scheme, legacyscheme.ParameterCodec, legacyscheme.Codecs)
42: 	// If you add a version here, be sure to add an entry in `k8s.io/kubernetes/cmd/kube-apiserver/app/aggregator.go with specific priorities.
43: 	// TODO refactor the plumbing to provide the information in the APIGroupInfo
44: 
45: 	if storageMap, err := p.v1alpha3Storage(apiResourceConfigSource, restOptionsGetter); err != nil {
46: 		return genericapiserver.APIGroupInfo{}, err
47: 	} else if len(storageMap) > 0 {
48: 		apiGroupInfo.VersionedResourcesStorageMap[resourcev1alpha3.SchemeGroupVersion.Version] = storageMap
49: 	}
50: 
51: 	if storageMap, err := p.v1beta1Storage(apiResourceConfigSource, restOptionsGetter); err != nil {
52: 		return genericapiserver.APIGroupInfo{}, err
53: 	} else if len(storageMap) > 0 {
54: 		apiGroupInfo.VersionedResourcesStorageMap[resourcev1beta1.SchemeGroupVersion.Version] = storageMap
55: 	}
56: 
57: 	return apiGroupInfo, nil
58: }
59: 
60: func (p RESTStorageProvider) v1alpha3Storage(apiResourceConfigSource serverstorage.APIResourceConfigSource, restOptionsGetter generic.RESTOptionsGetter) (map[string]rest.Storage, error) {
61: 	storage := map[string]rest.Storage{}
62: 
63: 	if resource := "deviceclasses"; apiResourceConfigSource.ResourceEnabled(resourcev1alpha3.SchemeGroupVersion.WithResource(resource)) {
64: 		deviceclassStorage, err := deviceclassstore.NewREST(restOptionsGetter)
65: 		if err != nil {
66: 			return nil, err
67: 		}
68: 		storage[resource] = deviceclassStorage
69: 	}
70: 
71: 	if resource := "resourceclaims"; apiResourceConfigSource.ResourceEnabled(resourcev1alpha3.SchemeGroupVersion.WithResource(resource)) {
72: 		resourceClaimStorage, resourceClaimStatusStorage, err := resourceclaimstore.NewREST(restOptionsGetter)
73: 		if err != nil {
74: 			return nil, err
75: 		}
76: 		storage[resource] = resourceClaimStorage
77: 		storage[resource+"/status"] = resourceClaimStatusStorage
78: 	}
79: 
80: 	if resource := "resourceclaimtemplates"; apiResourceConfigSource.ResourceEnabled(resourcev1alpha3.SchemeGroupVersion.WithResource(resource)) {
81: 		resourceClaimTemplateStorage, err := resourceclaimtemplatestore.NewREST(restOptionsGetter)
82: 		if err != nil {
83: 			return nil, err
84: 		}
85: 		storage[resource] = resourceClaimTemplateStorage
86: 	}
87: 
88: 	if resource := "resourceslices"; apiResourceConfigSource.ResourceEnabled(resourcev1alpha3.SchemeGroupVersion.WithResource(resource)) {
89: 		resourceSliceStorage, err := resourceslicestore.NewREST(restOptionsGetter)
90: 		if err != nil {
91: 			return nil, err
92: 		}
93: 		storage[resource] = resourceSliceStorage
94: 	}
95: 
96: 	return storage, nil
97: }
